        r := mod(x, y)
    }

    function decrement_t_uint256(value) -> ret {
        value := cleanup_t_uint256(value)
        if eq(value, 0x00) { panic_error_0x11() }
        ret := sub(value, 1)
    }

    function checked_div_t_uint256(x, y) -> r {
        x := cleanup_t_uint256(x)
        y := cleanup_t_uint256(y)
